// server/monitor.ts
var PRICE_DROP_STEP = 0.985;
var PRICE_FLOOR_RATIO = 0.82;
function formatUSD(n) {
  return n.toLocaleString("en-US", {
    style: "currency",
    currency: "USD",
    maximumFractionDigits: 0
  });
}
function nextPrice(prev, base) {
  const floor = Math.round(base * PRICE_FLOOR_RATIO);
  return Math.max(Math.round(prev * PRICE_DROP_STEP), floor);
}
function dropsThisRun(listingId) {
  const dayBucket = Math.floor(Date.now() / (1e3 * 60 * 60 * 24));
  let h = dayBucket >>> 0;
  for (let i = 0; i < listingId.length; i++) {
    h = h * 31 + listingId.charCodeAt(i) >>> 0;
  }
  return h % 2 === 0;
}
async function runMonitor() {
  const inventory = await inventoryProvider.getInventory();
  const byId = new Map(inventory.map((l) => [l.id, l]));
  let priceDrops = 0;
  let newMatches = 0;
  const savedVehicles2 = await getAllSavedVehicles();
  const trackable = savedVehicles2.filter((v) => !!v.listingId);
  for (const v of trackable) {
    const listing = byId.get(v.listingId);
    const base = v.priceAtSave ?? listing?.price ?? v.lastKnownPrice ?? null;
    const prev = v.lastKnownPrice ?? v.priceAtSave ?? listing?.price ?? null;
    if (base == null || prev == null) continue;
    const neverDropped = prev === base;
    const np = neverDropped || dropsThisRun(v.listingId) ? nextPrice(prev, base) : prev;
    if (np < prev) {
      await recordPrice({ listingId: v.listingId, vin: v.vin, price: np });
      await updateSavedVehiclePrice(v.id, np);
      priceDrops += 1;
      await addNotification({
        userId: v.userId,
        type: "price_drop",
        title: `Price drop on ${v.nickname ?? `${v.make ?? ""} ${v.model ?? ""}`.trim()}`,
        body: `Now ${formatUSD(np)} \u2014 down ${formatUSD(prev - np)} from ${formatUSD(
          prev
        )} (${formatUSD(base)} when you saved it).`,
        listingId: v.listingId,
        vin: v.vin,
        data: { from: prev, to: np, base }
      });
    }
  }
  const searches = await getActiveSavedSearches();
  for (const s of searches) {
    const criteria = s.criteria;
    let ranked;
    try {
      ranked = rankInventory(inventory, criteria, 8);
    } catch {
      await markSavedSearchChecked(s.id, s.lastSeenListingIds ?? []);
      continue;
    }
    const currentIds = ranked.map((m) => m.listing.id);
    const prevSeen = s.lastSeenListingIds ?? null;
    const fresh = prevSeen == null ? currentIds : currentIds.filter((id) => !prevSeen.includes(id));
    if (fresh.length > 0) {
      newMatches += fresh.length;
      const sample = fresh.map((id) => byId.get(id)).filter((l) => !!l).slice(0, 3).map((l) => `${l.year} ${l.make} ${l.model} \u2014 ${formatUSD(l.price)}`);
      await addNotification({
        userId: s.userId,
        type: "new_match",
        title: `${fresh.length} new match${fresh.length === 1 ? "" : "es"} for "${s.name ?? "your saved search"}"`,
        body: sample.join(" \xB7 "),
        savedSearchId: s.id,
        data: { listingIds: fresh }
      });
    }
    await markSavedSearchChecked(s.id, currentIds);
  }
  return {
    priceDrops,
    newMatches,
    checkedSearches: searches.length,
    checkedVehicles: trackable.length
  };
}

// server/_serverless/cron.ts
async function handler(req, res) {
  if (ENV.cronSecret && req.headers.authorization !== `Bearer ${ENV.cronSecret}`) {
    res.status(401).json({ ok: false, error: "Unauthorized" });
    return;
  }
  try {
    const result = await runMonitor();
    res.status(200).json({ ok: true, ...result });
  } catch (error) {
    console.error("[cron/monitor] failed:", error);
    res.status(500).json({ ok: false, error: String(error) });
  }
}
export {
  handler as default
};
